#!/usr/bin/env bun
/**
 * Unspeech Lexicon Coverage Benchmark
 *
 * Measures how much symbol mass is captured by a top-K UTF-16 code-unit
 * lexicon across representative language mixes.
 */

import { pathToFileURL } from 'node:url';

interface Corpus {
  name: string;
  text: string;
}

interface CoverageRow {
  k: number;
  coveragePct: number;
}

interface CoverageReport {
  name: string;
  totalCodeUnits: number;
  uniqueCodeUnits: number;
  rows: CoverageRow[];
}

const K_VALUES = [64, 128, 256, 512, 1024, 2048];

function formatPct(v: number): string {
  return `${v.toFixed(2)}%`;
}

function countCodeUnits(text: string): Map<number, number> {
  const counts = new Map<number, number>();
  for (let i = 0; i < text.length; i++) {
    const unit = text.charCodeAt(i);
    counts.set(unit, (counts.get(unit) ?? 0) + 1);
  }
  return counts;
}

function coverageForTopK(counts: Map<number, number>, k: number): number {
  const entries = [...counts.entries()].sort((a, b) => b[1] - a[1]);
  const total = entries.reduce((sum, [, count]) => sum + count, 0);
  const captured = entries
    .slice(0, Math.min(k, entries.length))
    .reduce((sum, [, count]) => sum + count, 0);
  return total === 0 ? 0 : (captured / total) * 100;
}

function buildCorpora(): Corpus[] {
  const english = (
    'Compression is representation under constraints. ' +
    'Unspeech treats shared context as a transport primitive. '
  ).repeat(180);

  const latinExtended = (
    'Français déjà vu naïve façade coöperate. ' +
    'Español pingüino corazón acción. ' +
    'Português informação eficiência. '
  ).repeat(140);

  const cjk = (
    '数据压缩需要上下文。通信可以通过共享词典变得更高效。' +
    '日本語の文章を含むテストです。韓国어도 함께 포함합니다。'
  ).repeat(120);

  const mixedGlobal = (
    `English العربية हिन्दी 中文 日本語 한국어 русский язык ${
      String.fromCodePoint(0x1f642)
    }${String.fromCodePoint(0x1f680)} ` +
    'state synchronization across channels with residual deltas. '
  ).repeat(160);

  const emojiHeavy = (
    [
      0x1f642, 0x1f680, 0x1f525, 0x2728, 0x1f9e0,
      0x1f4e1, 0x1f300, 0x1f3af, 0x1f9e9, 0x1f4be, 0x1f512,
    ]
      .map((cp) => String.fromCodePoint(cp))
      .join('') + 'lol omg '
  ).repeat(240);

  const wideSpectrum = (() => {
    const symbols: string[] = [];

    for (let cp = 0x20; cp <= 0x7e; cp++) symbols.push(String.fromCodePoint(cp)); // ASCII
    for (let cp = 0x370; cp <= 0x3ff; cp++) symbols.push(String.fromCodePoint(cp)); // Greek
    for (let cp = 0x400; cp <= 0x4ff; cp++) symbols.push(String.fromCodePoint(cp)); // Cyrillic
    for (let cp = 0x600; cp <= 0x6ff; cp++) symbols.push(String.fromCodePoint(cp)); // Arabic
    for (let cp = 0x900; cp <= 0x97f; cp++) symbols.push(String.fromCodePoint(cp)); // Devanagari
    for (let cp = 0x3040; cp <= 0x30ff; cp++) symbols.push(String.fromCodePoint(cp)); // Hiragana+Katakana
    for (let cp = 0x4e00; cp <= 0x4eff; cp++) symbols.push(String.fromCodePoint(cp)); // CJK subset
    for (let cp = 0x1f600; cp <= 0x1f64f; cp++) symbols.push(String.fromCodePoint(cp)); // Emoji faces

    // Zipf-like skew: ASCII and punctuation appear more frequently than the tail.
    const out: string[] = [];
    for (let i = 0; i < symbols.length; i++) {
      const s = symbols[i]!;
      const repeats =
        i < 128 ? 24 :
        i < 512 ? 8 :
        i < 1024 ? 3 :
        1;
      for (let r = 0; r < repeats; r++) out.push(s);
    }
    return out.join('');
  })();

  return [
    { name: 'english-ascii-heavy', text: english },
    { name: 'latin-extended', text: latinExtended },
    { name: 'cjk-mix', text: cjk },
    { name: 'mixed-global', text: mixedGlobal },
    { name: 'emoji-heavy', text: emojiHeavy },
    { name: 'wide-unicode-spectrum', text: wideSpectrum },
  ];
}

function evaluateCorpus(corpus: Corpus): CoverageReport {
  const counts = countCodeUnits(corpus.text);
  return {
    name: corpus.name,
    totalCodeUnits: corpus.text.length,
    uniqueCodeUnits: counts.size,
    rows: K_VALUES.map((k) => ({
      k,
      coveragePct: coverageForTopK(counts, k),
    })),
  };
}

function printReport(report: CoverageReport): void {
  console.log(`corpus: ${report.name}`);
  console.log(`  total code units : ${report.totalCodeUnits}`);
  console.log(`  unique code units: ${report.uniqueCodeUnits}`);
  for (const row of report.rows) {
    console.log(`  top-${String(row.k).padEnd(4)} coverage: ${formatPct(row.coveragePct)}`);
  }
  console.log('');
}

/**
 * Runs the gnosis command-line workflow.
 */
export async function main(): Promise<void> {
  const corpora = buildCorpora();
  for (const corpus of corpora) {
    printReport(evaluateCorpus(corpus));
  }
}

const invokedPath = process.argv[1];
if (invokedPath && import.meta.url === pathToFileURL(invokedPath).href) {
  main().catch((error: unknown) => {
    console.error(error);
    process.exit(1);
  });
}
